SELECT id, material_id AS materialId, amount, reason, change_type AS changeType, change_target_id AS changeTargetId, remark, add_time AS addTime, student_id AS studentId, staff_id AS staffId FROM material_record WHERE deleted = 0
AND material_id = #{query.materialId}
AND change_type = #{query.changeType}
AND student_id = #{query.studentId}
AND staff_id = #{query.staffId}
ORDER BY add_time DESC
